import { Vex } from 'vex-sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });

const agentResult = await executor.invoke({ input: userQuery });

const verified = await vex.verify(agentResult.output, {
  suite: [
    'code_execution',
    'security_scan',
    'credential_detector',
    'dependency_scan',
    'license_compliance'
  ],
  timeout: '30s'
});

if (verified.passed) {
  return verified.output;
} else {
  throw new Error(`Verification failed: ${JSON.stringify(verified.errors)}`);
}
